final:
module top_module(err_ALUOP,func,alu_control_out);input [5:0] err_ALUOP;
input [5:0] func;
output reg [5:0] alu_control_out;

always@(err_ALUOP,func)
begin
    if(err_ALUOP == 6'b111111)
        begin
            alu_control_out = func;
        end
    else
        begin 
            alu_control_out = err_ALUOP;
        end

end


endmodule
